mapper.update:
UPDATE setmeal
SET
category_id=#{categoryId},
name=#{name},
price=#{price},
image=#{image},
update_time=NOW(),
update_user=#{updateUser}

    ,status= #{status}


    ,description= #{description}

WHERE id= #{id}

mapper.select:
SELECT s.id,s.category_id,s.name,s.price,s.status,s.description,s.image,s.update_time,c.name AS category_name
FROM setmeal AS s
LEFT JOIN category AS c ON s.category_id=c.id


        category_id=#{categoryId}


        status=#{status}


        name LIKE '%#{name}%'
